@namespace sv_3b73a79dc18145128785080c90e74334.Components

<div class="@DropZoneClass"
     @ondragenter="HandleDragEnter"
     @ondragover="HandleDragOver"
     @ondragleave="HandleDragLeave"
     @ondrop="HandleDrop"
     @ondragenter:preventDefault
     @ondragover:preventDefault
     @ondrop:preventDefault>
    <p class="drop-zone-text">Drag and drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in _files)
        {
            <li class="file-entry @(entry.IsOversize ? "file-error" : "")">
                @if (entry.IsOversize)
                {
                    <span class="file-info">@entry.Info.Name — File exceeds 10 MB limit (@FormatSize(entry.Info.Size))</span>
                }
                else
                {
                    <span class="file-info">@entry.Info.Name — @FormatSize(entry.Info.Size) — @entry.Info.Type</span>
                }
                <button class="btn-remove" @onclick="() => RemoveFile(entry)">Remove</button>
            </li>
        }
    </ul>
}

<style>
    .drop-zone {
        border: 2px dashed #6c757d;
        border-radius: 8px;
        padding: 2rem;
        text-align: center;
        transition: border-color 0.2s, background-color 0.2s;
        min-height: 120px;
        display: flex;
        align-items: center;
        justify-content: center;
    }

    .drop-zone-highlight {
        border-color: #0d6efd;
        background-color: rgba(13, 110, 253, 0.05);
    }

    .drop-zone-text {
        color: #6c757d;
        margin: 0;
    }

    .file-list {
        list-style: none;
        padding: 0;
        margin-top: 1rem;
    }

    .file-entry {
        display: flex;
        justify-content: space-between;
        align-items: center;
        padding: 0.5rem 0.75rem;
        border: 1px solid #dee2e6;
        border-radius: 4px;
        margin-bottom: 0.5rem;
    }

    .file-entry.file-error {
        border-color: #dc3545;
        background-color: rgba(220, 53, 69, 0.05);
        color: #dc3545;
    }

    .btn-remove {
        background: none;
        border: 1px solid #dc3545;
        color: #dc3545;
        border-radius: 4px;
        padding: 0.25rem 0.5rem;
        cursor: pointer;
    }

    .btn-remove:hover {
        background-color: #dc3545;
        color: #fff;
    }
</style>

using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Web;

namespace sv_3b73a79dc18145128785080c90e74334.Components;

public partial class FileDropZone : ComponentBase
{
    private const long MaxFileSizeBytes = 10 * 1024 * 1024; // 10 MB

    private bool _isDragOver;
    private readonly List<FileEntry> _files = new();

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private string DropZoneClass => _isDragOver ? "drop-zone drop-zone-highlight" : "drop-zone";

    private void HandleDragEnter(DragEventArgs e) => _isDragOver = true;

    private void HandleDragOver(DragEventArgs e) => _isDragOver = true;

    private void HandleDragLeave(DragEventArgs e) => _isDragOver = false;

    private async Task HandleDrop(DragEventArgs e)
    {
        _isDragOver = false;

        if (e.DataTransfer?.Items is not null)
        {
            foreach (var item in e.DataTransfer.Items)
            {
                if (item.Kind == "file" && item.Type is not null)
                {
                    var info = new FileInfo(item.Type, item.Size, item.Type);
                    var entry = new FileEntry(info, item.Size > MaxFileSizeBytes);
                    _files.Add(entry);
                }
            }
        }

        await NotifyParent();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _files
            .Where(f => !f.IsOversize)
            .Select(f => f.Info)
            .ToList();

        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes)
    {
        return bytes switch
        {
            < 1024 => $"{bytes} B",
            < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
            _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
        };
    }

    private sealed record FileEntry(FileInfo Info, bool IsOversize);
}

public record FileInfo(string Name, long Size, string Type);

