using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Web;

namespace sv_3b73a79dc18145128785080c90e74334.Components;

public partial class FileDropZone : ComponentBase
{
    private const long MaxFileSizeBytes = 10 * 1024 * 1024; // 10 MB

    private bool _isDragOver;
    private readonly List<FileEntry> _files = new();

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private string DropZoneClass => _isDragOver ? "drop-zone drop-zone-highlight" : "drop-zone";

    private void HandleDragEnter(DragEventArgs e) => _isDragOver = true;

    private void HandleDragOver(DragEventArgs e) => _isDragOver = true;

    private void HandleDragLeave(DragEventArgs e) => _isDragOver = false;

    private async Task HandleDrop(DragEventArgs e)
    {
        _isDragOver = false;

        if (e.DataTransfer?.Items is not null)
        {
            foreach (var item in e.DataTransfer.Items)
            {
                if (item.Kind == "file" && item.Type is not null)
                {
                    var info = new FileInfo(item.Type, item.Size, item.Type);
                    var entry = new FileEntry(info, item.Size > MaxFileSizeBytes);
                    _files.Add(entry);
                }
            }
        }

        await NotifyParent();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _files
            .Where(f => !f.IsOversize)
            .Select(f => f.Info)
            .ToList();

        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes)
    {
        return bytes switch
        {
            < 1024 => $"{bytes} B",
            < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
            _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
        };
    }

    private sealed record FileEntry(FileInfo Info, bool IsOversize);
}

public record FileInfo(string Name, long Size, string Type);

