using Microsoft.AspNetCore.Components;
using Microsoft.JSInterop;

namespace sv_3b73a79dc18145128785080c90e74334.Components;

public partial class FileDropZone : ComponentBase, IAsyncDisposable
{
    private const long MaxFileSizeBytes = 10 * 1024 * 1024; // 10 MB

    private bool _isDragOver;
    private readonly List<FileEntry> _files = new();
    private ElementReference _dropZoneRef;
    private IJSObjectReference? _jsModule;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;

    [Inject] private IJSRuntime JS { get; set; } = default!;

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private string DropZoneClass => _isDragOver ? "drop-zone drop-zone-highlight" : "drop-zone";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv_3b73a79dc18145128785080c90e74334/Components/FileDropZone.razor.js");
            _dotNetRef = DotNetObjectReference.Create(this);
            await _jsModule.InvokeVoidAsync("initDropZone", _dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public void OnDragEnter() { _isDragOver = true; StateHasChanged(); }

    [JSInvokable]
    public void OnDragLeave() { _isDragOver = false; StateHasChanged(); }

    [JSInvokable]
    public async Task OnFilesDropped(DroppedFileDto[] files)
    {
        _isDragOver = false;

        foreach (var file in files)
        {
            var info = new FileInfo(file.Name, file.Size, file.Type);
            var entry = new FileEntry(info, file.Size > MaxFileSizeBytes);
            _files.Add(entry);
        }

        await NotifyParent();
        StateHasChanged();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _files
            .Where(f => !f.IsOversize)
            .Select(f => f.Info)
            .ToList();

        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes)
    {
        return bytes switch
        {
            < 1024 => $"{bytes} B",
            < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
            _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
        };
    }

    public async ValueTask DisposeAsync()
    {
        if (_jsModule is not null)
        {
            await _jsModule.InvokeVoidAsync("dispose", _dropZoneRef);
            await _jsModule.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }

    private sealed record FileEntry(FileInfo Info, bool IsOversize);

    public sealed class DroppedFileDto
    {
        public string Name { get; set; } = "";
        public long Size { get; set; }
        public string Type { get; set; } = "";
    }
}

public record FileInfo(string Name, long Size, string Type);

