const dropZones = new Map();

export function initDropZone(element, dotNetRef) {
    const handler = {
        dragenter(e) {
            e.preventDefault();
            dotNetRef.invokeMethodAsync('OnDragEnter');
        },
        dragover(e) {
            e.preventDefault();
        },
        dragleave(e) {
            if (!element.contains(e.relatedTarget)) {
                dotNetRef.invokeMethodAsync('OnDragLeave');
            }
        },
        drop(e) {
            e.preventDefault();
            const files = [];
            for (const file of e.dataTransfer.files) {
                files.push({ name: file.name, size: file.size, type: file.type || 'application/octet-stream' });
            }
            dotNetRef.invokeMethodAsync('OnFilesDropped', files);
        }
    };

    element.addEventListener('dragenter', handler.dragenter);
    element.addEventListener('dragover', handler.dragover);
    element.addEventListener('dragleave', handler.dragleave);
    element.addEventListener('drop', handler.drop);

    dropZones.set(element, handler);
}

export function dispose(element) {
    const handler = dropZones.get(element);
    if (handler) {
        element.removeEventListener('dragenter', handler.dragenter);
        element.removeEventListener('dragover', handler.dragover);
        element.removeEventListener('dragleave', handler.dragleave);
        element.removeEventListener('drop', handler.drop);
        dropZones.delete(element);
    }
}

